
import { defineComponent, ref, onMounted, nextTick, onUnmounted } from "vue";
import { useRoute } from "vue-router";
import { UiData, UiOtherDataArr, IReportData, QueryObj } from "./common";

import Box from "./Box.vue";
import { getReport, getReportByStr } from "../../api/report";
import { getmmdd, getmmss, getyyyymmdd } from '../../utils/time';
import sensors from '../../utils/sensors';

export default defineComponent({
  components: {
    Box,
  },
  setup() {
    const time = ref<string>("");
    const title = ref<string>("");
    const uiDataObj = ref<UiData>({
      title: "",
      starNum: 0,
      rate: 0,
      rateStr: "0%",
      answerNum: 0,
      overNum: 0,
      wrongNum: 0,
      reviseNum: 0,
      evaluate: "...",
    });
    const otherDataArr = ref<UiOtherDataArr>([]);
    const hStar = ref<string>(
      "https://static0.xesimg.com/xpp-parent-fe/newStarA.png"
    );
    const yStar = ref<string>(
      "https://static0.xesimg.com/xpp-parent-fe/newStarL.png"
    );

    const route = useRoute();
    const { query = {} } = route;
    const { stu_id, plan_id, str, Authorization, channel } = query as QueryObj;

    let planReportDate = '';
    let pageStartDate = Date.now();
    let isFinish = 0;

    onMounted(() => {
      document.title = "详细报告";
      myGetReport();
    });
    onUnmounted(() => {
      sensors.track('study_report_leave', {
        report_new_date: getyyyymmdd(planReportDate) || '',
        // report_date: getyyyymmdd(planReportDate),
        // report_exit_time: '',
        report_show_duration: (Date.now() - pageStartDate) / 1000 || 0,
        report_is_finish: isFinish
      })
    })

    const circularProgress = (percent: number) => {
      try {
        const canvas = document.getElementById("myCanvas") as HTMLCanvasElement;
        const { width, height } = canvas.getBoundingClientRect();
        const ctx = canvas.getContext("2d") as any;

        const dpr = window.devicePixelRatio;
        canvas.width = width * dpr;
        canvas.height = height * dpr;
        ctx.scale(dpr, dpr);

        // console.log(width, height, canvas.width);
        // 清除画布
        ctx.clearRect(0, 0, width, height);
        // 保存
        ctx.save();

        /* 画曲线 */
        const drawCircle = (ctx: any, config: any) => {
          const { x, y, radius, startAngle, endAngle, color, lineWidth } = config;
          ctx.beginPath();
          ctx.arc(x, y, radius, startAngle, endAngle, false);
          // 设定曲线粗细度
          ctx.lineWidth = lineWidth;
          // 给曲线着色
          ctx.strokeStyle = color;
          // 连接处样式
          ctx.lineCap = "round";
          // 给环着色
          ctx.stroke();
          ctx.closePath();
        };

        /* 开始圆环 */
        const circleConfig = {
          /* 圆心坐标 */
          x: width / 2,
          y: height / 2,
          /* 半径，下方出现的150都是半径 */
          radius: width / 2 - 20,
          /* 环的宽度 */
          lineWidth: 10,
          // lineWidth: 50,
          /* 开始的度数-从上一个结束的位置开始 */
          startAngle: 0, // 注意这里的0是3点钟方向，而非12点方向，和数学里的不一样
          /* 结束的度数 */
          endAngle: 200,
          color: "#F6ECCF",
        };

        /* 灰色的圆环 */
        drawCircle(ctx, circleConfig);
        // return;

        /* 有色的圆环 */
        const holeCicle = 2 * Math.PI;

        drawCircle(ctx, {
          ...circleConfig,
          /* 从-90度的地方开始画 */
          startAngle: -0.5 * Math.PI, // 把起始点改成数学里的12点方向
          endAngle: -0.5 * Math.PI + percent * holeCicle,
          color: "#FFBE14",
        });
      } catch (error) {
        console.error('circularProgress', error);
      }
    };

    const myGetReport = async (): Promise<void> => {
      try {
        let res!: any;
        // 正常跳转
        if (plan_id && stu_id && Authorization) {
          res =
            (await getReport({
              stu_id,
              plan_id,
              myHeaders: {
                Authorization,
              }
            })) || {};
        } else if (str) {
          // 加密
          res =
            (await getReportByStr({
              str: decodeURIComponent(str) || '',
            })) || {};
        }
        const {
          plan_report_date = "",
          plan_name = "",
          plan_star = 0,
          accurate_rate = 0,
          question_num = 0,
          over_fulfill_num = 0,
          wrong_num = 0,
          correct_num = 0,
          t_evaluate = "",
          stage_list = [],
        } = res as IReportData;
        planReportDate = plan_report_date.replace(/-/g, '/');
        time.value = getmmdd(plan_report_date.replace(/-/g, '/'));
        title.value = plan_name;

        let myTitle = '';
        /** 
         * 完成 >0 < 2
         * 优秀 >= 2  <3
         * 完美 ==3
         */
        const myStarNum = +plan_star / 2;
        if (myStarNum === 3) {
          myTitle = '完美';
        } else if (myStarNum >=2) {
          myTitle = '优秀';
        } else {
          myTitle = '完成';
        }
        uiDataObj.value = {
          title: myTitle,
          starNum: myStarNum,
          rate: accurate_rate,
          rateStr: `${(accurate_rate* 100).toFixed(0)}%`,
          answerNum: question_num,
          overNum: over_fulfill_num,
          wrongNum: wrong_num,
          reviseNum: correct_num,
          evaluate: t_evaluate,
        };

        otherDataArr.value = stage_list.map((item) => {
          const { stage_name = '', duration = 0, accurate_rate = 0, is_over_fulfill = false, question_num = 0 } = item;
          return {
            title: stage_name,
            isExcess: is_over_fulfill,
            subjectNum: question_num,
            correctRate: `${(accurate_rate* 100).toFixed(0)}%`,
            useTime: getmmss(+duration),
          };
        });

        nextTick(() => {
          circularProgress(accurate_rate);
        })


        pageStartDate = Date.now();
        isFinish = t_evaluate ? 1 : 0;

        sensors.track('study_report_enter', {
          report_new_date: getyyyymmdd(planReportDate) || '',
          // report_open_time: '',
          // report_date: getyyyymmdd(planReportDate) || '',
          report_open_channel: str ? 1 : ((channel && +channel === 2) ? 2 : 3),
          report_is_finish: isFinish
        })
        
      } catch (error) {
        console.error('myGetReport', error);
      }
    };

    return {
      title,
      hStar,
      yStar,
      time,
      uiDataObj,
      otherDataArr,
    };
  },
});
