import md5 from "md5";
import { AxiosPromise } from 'axios';
import http from '../utils/http';

import {APPINFO} from "./config";

interface IGetReportData {
  stu_id: string;
  plan_id: string;
  myHeaders: {
    [propName: string]: any;
  }
}

interface IGetReportDataByStr {
  str: string;
}

export const getReport = (data: IGetReportData): AxiosPromise<any> => {
  return http({
    url: '/mfx/api/v1/parent/plan/report',
    params: data,
    headers: data.myHeaders
  })
}

export const getReportByStr = (data: IGetReportDataByStr): AxiosPromise<any> => {
  return http({
    url: '/mfx/api/v1/share/content',
    params: data,
  })
}

export const getScancode = (data: IGetReportDataByStr): AxiosPromise<any> => {
    const app_key = APPINFO.APPKEY;
    const app_secret = APPINFO.APPSECRET;
    const timestamp = Math.floor(Date.now() / 1000);
    const headerStr = app_key + timestamp + app_secret;
    const sign = md5(headerStr);
    return http({
        headers: {
            'X-Tal-Timestamp': timestamp,
            'X-Tal-AppKey': app_key,
            'X-Tal-Sign': sign
        },
      url: '/bixin/search/api/h5/v1/wechat/company/setting',
      params: data,
    })
}